import os
import cv2
import numpy as np
from sklearn import svm
from sklearn import preprocessing
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename

app = Flask(__name__)

# Load haarcascade for face detection
face_cascade = cv2.CascadeClassifier(cv2.data.haarcascades + 'haarcascade_frontalface_default.xml')

# Prepare training data
def prepare_training_data(data_folder_path):
    dirs = os.listdir(data_folder_path)
    faces = []
    labels = []
    
    for dir_name in dirs:
        label = dir_name
        subject_dir_path = data_folder_path + "/" + dir_name
        subject_images_names = os.listdir(subject_dir_path)
        
        for image_name in subject_images_names:
            image_path = subject_dir_path + "/" + image_name
            image = cv2.imread(image_path)
            face, rect = detect_face(image)
            if face is not None:
                faces.append(face)
                labels.append(label)
                
    return faces, labels

# Detect face
def detect_face(img):
    gray = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)
    faces = face_cascade.detectMultiScale(gray, scaleFactor=1.2, minNeighbors=5);
    if (len(faces) == 0):
        return None, None
    (x, y, w, h) = faces[0]
    return gray[y:y+w, x:x+h], faces[0]

# Train model
faces, labels = prepare_training_data("employee_photos")
le = preprocessing.LabelEncoder()
labels = le.fit_transform(labels)
face_recognizer = svm.SVC(probability=True)
face_recognizer.fit(faces, labels)

# API endpoint
@app.route('/api/recognize', methods=['POST'])
def recognize():
    file = request.files['image']
    filename = secure_filename(file.filename)
    file.save(filename)
    image = cv2.imread(filename)
    face, rect = detect_face(image)
    label = face_recognizer.predict(face)
    probabilities = face_recognizer.predict_proba(face)
    return jsonify({'label': le.inverse_transform(label), 'probabilities': probabilities.tolist()})

if __name__ == '__main__':
    app.run(debug=True)